content.query:
let win = {TimeRange};
let reqs = requests | where timestamp > ago(win) | summarize n=count(), p95=percentile(duration,95);
let exns = exceptions | where timestamp > ago(win) | summarize n=count();
let deps = dependencies | where timestamp > ago(win) | summarize n=count(), fails=countif(success==false);
let ces  = customEvents | where timestamp > ago(win) | summarize n=count();
union withsource=Metric
 (reqs | extend Metric='Requests',         Value=tostring(n), Sub=strcat('p95 ', tostring(round(p95,0)), ' ms')),
 (exns | extend Metric='Exceptions',       Value=tostring(n), Sub=''),
 (deps | extend Metric='Dependencies',     Value=tostring(n), Sub=strcat(tostring(fails), ' failed')),
 (ces  | extend Metric='Custom events',    Value=tostring(n), Sub='')
| project Metric, Value, Sub
